body.script:
(function(){

  var urls = [
    "https://cdn.jsdelivr.net/gh/Darkdragonzxs/zd-pages@latest/zodiac.html",
    "https://raw.githack.com/Darkdragonzxs/zd-pages/main/zodiac.html",
    "https://raw.githubusercontent.com/Darkdragonzxs/zd-pages/main/zodiac.html"
  ];

  function safe(html){
    return html.replace(/<\/script>/gi,'');
  }

  function load(i){
    if(i >= urls.length){
      document.body.innerHTML = "Failed to load";
      return;
    }

    fetch(urls[i]).then(function(r){
      if(!r.ok) throw 0;
      return r.text();
    }).then(function(html){

      html = safe(html);

      document.open();
      document.write(html);
      document.close();

    }).catch(function(){
      load(i+1);
    });
  }

  load(0);

})();
